1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
3	
4	const BASE_PREMIUM: Record<string, number> = {
5	  sword: 100,
6	  amulet: 60,
7	  staff: 80,
8	  potion: 40,
9	  rune: 25,
10	  moonstone: 25,
11	};
12	
13	type Item = { type: string };
14	type Step = { op: "quote"; items: Item[] };
15	type Scenario = { customer: { yearsWithMHPCO: number }; steps: Step[] };
16	
17	const basePremiumOf = (item: Item): number => BASE_PREMIUM[item.type];
18	
19	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
20	const BLOCK_SIZE = 3;
21	const BLOCK_BASE_PREMIUM = 60;
22	
23	const sumBasePremiums = (items: Item[]): number =>
24	  items.reduce((sum, item) => sum + basePremiumOf(item), 0);
25	
26	const allAlike = (items: Item[]): boolean =>
27	  items.every((it) => it.type === items[0].type);
28	
29	const componentSubtotalOf = (components: Item[]): number => {
30	  if (components.length === BLOCK_SIZE && allAlike(components)) {
31	    return BLOCK_BASE_PREMIUM;
32	  }
33	  return sumBasePremiums(components);
34	};
35	
36	const policyBaseOf = (items: Item[]): number => {
37	  const components = items.filter((it) => COMPONENT_TYPES.has(it.type));
38	  const mainItems = items.filter((it) => !COMPONENT_TYPES.has(it.type));
39	  return sumBasePremiums(mainItems) + componentSubtotalOf(components);
40	};
41	
42	const firstInsuranceSurchargeOf = (policyBase: number): number =>
43	  policyBase * FIRST_INSURANCE_SURCHARGE_RATE;
44	
45	const roundUpInMHPCOFavor = (amount: number): number => Math.ceil(amount);
46	
47	const quotePremium = (items: Item[]): number => {
48	  const policyBase = policyBaseOf(items);
49	  const rawPremium = policyBase + firstInsuranceSurchargeOf(policyBase) + PROCESSING_FEE;
50	  return roundUpInMHPCOFavor(rawPremium);
51	};
52	
53	export const processScenario = (scenario: Scenario): { results: Array<{ premium: number }> } => {
54	  const results = scenario.steps.map((step) => ({ premium: quotePremium(step.items) }));
55	  return { results };
56	};
